---战斗阴影
---@class LBattleViewFade
local LBattleViewFade = classX("LBattleViewFade", nil)
local typeSpriteRenderer = typeof(UnityEngine.SpriteRenderer)

local _UILayerMask = LayerMask.NameToLayer("UI")
local PJXUtil = PJXUtil

function LBattleViewFade:ctor(viewMgr)
    ---@type LBattleViewMgr
    self._viewMgr = viewMgr
end

function LBattleViewFade:Initialize(para)
    self._parentRoot = para.parentRoot
    self._startTime = para.startTime

    self._playTime = self._startTime + para.playTime

    self._dissipateTime = self._playTime + para.dissipateTime

    self._fadeOutStart = self._playTime
    self._fadeOutSpan = para.dissipateTime
    self._fadeOutEnd = self._dissipateTime

    self._fadeInStart = self._startTime
    self._fadeInSpan = para.dissipateTime
    self._fadeInEnd = self._startTime+ self._fadeInSpan

    self._renderLayer = para.layer
    self._renderOrder = para.order

    self._callback = para.callback

    self._alpha = checknumber(para.alpha)


    self._type = para.type or LBattleViewFade.TYPE_TWO

    self._side = para.side
    self._index = para.index
    if IsValid(self._fadeGo) then
        self._isDisposed = false
        self._isPlaying = false
        return
    else
        self:InitFadeObj()
    end
end

function LBattleViewFade:InitFadeObj()
    if self._fadeGo then
        LxResUtil.DestroyObject(self._fadeGo)
        self._fadeGo= nil
    end

    local madFadeTemplate  = self._viewMgr:GetFadeTemplate()

    local instanceGo = LxResUtil.NewObject(madFadeTemplate)

    self._fadeGo = instanceGo
    local trans = instanceGo.transform
    trans:SetParent(self._parentRoot, false)

    local scale = Vector3.New(1,1,1)
    if self._type == LBattleViewFade.TYPE_THREE then
        scale = Vector3.New(100,100,1)
        local dpGo = instanceGo.gameObject
        if dpGo.layer ~= _UILayerMask then
            PJXUtil.UpdateChildLayer(instanceGo, _UILayerMask, true)
        end
    end
    trans.localScale = scale
    trans.localPosition= Vector3.zero
    self:UpdateRender()
    self:SetAlpha(0)
    local show = self._isPlaying == true
    ShowObject(instanceGo,show)
end

function LBattleViewFade:Dispose()
    if self._isDisposed then return end
    self:PlayCallback()
    if self._fadeGo then
        LxResUtil.DestroyObject(self._fadeGo)
        self._fadeGo= nil
    end
    table.dispose(self)
    self._isDisposed = true
end
-----------------------------------------------------------------
function LBattleViewFade:OnUpdate(time, deltaTime)
    if self._isDisposed then return false end
    if not self._isPlaying then
        if self._startTime <= time then
            self._isPlaying = true
            self._sendShow = false
            self._sendHide = false
            ShowObject(self._fadeGo,true)
        end
    else
        if time < self._fadeInEnd and time >= self._fadeInStart then
            if self._fadeInSpan>0 then
                local timeLeft =  time - self._fadeInStart
                local percent =Mathf.Lerp(0,1,timeLeft/self._fadeInSpan)
                local alpha = percent * self._alpha
                self:SetAlpha(alpha)
            end

            if self._type == LBattleViewFade.TYPE_TWO and not self._sendHide  then
                self._sendHide = true
                FireEvent(EventNames.BATTLE_CHANGE_WND_SHOW,false,self._fadeInSpan,self._side,self._index)
            end

        elseif time > self._fadeInEnd and time < self._fadeOutStart then
            self:SetAlpha(self._alpha)
        elseif time < self._fadeOutEnd and time >= self._fadeOutStart then
            if self._fadeOutSpan> 0 then
                local timeLeft = self._fadeOutEnd - time
                local percent =Mathf.Lerp(0,1,timeLeft/self._fadeOutSpan)
                local alpha = percent * self._alpha
                self:SetAlpha(alpha)
            end

            if self._type == LBattleViewFade.TYPE_TWO and not self._sendShow then
                self._sendShow = true
                FireEvent(EventNames.BATTLE_CHANGE_WND_SHOW,true,self._fadeOutSpan,self._side,self._index)
            end
        end

        if self._dissipateTime < time  then
            self:PlayCallback()
            return false
        end
    end
    return true
end

function LBattleViewFade:PlayCallback()
    if self._callback then
        local callback = self._callback
        self._callback = nil
        callback()
    end
end

function LBattleViewFade:SetRenderOrder(order)
    self._renderOrder = order
    self:UpdateRender()
end

function LBattleViewFade:UpdateRender()
    if not IsValid(self._fadeGo) then
        return
    end
    if not self._sr then
        self._sr = self._fadeGo:GetComponent(typeSpriteRenderer)
    end

    self._sr.sortingOrder = self._renderOrder or 0
    self._sr.sortingLayerName = self._renderLayer or "Default"
end

function LBattleViewFade:SetAlpha(alpha)
    if not IsValid(self._fadeGo) then
        return
    end
    if not self._sr then
        self._sr = self._fadeGo:GetComponent(typeSpriteRenderer)
    end

    local value = alpha/255
    self._sr.color = Color.New(0, 0, 0, value)
end

return LBattleViewFade